package main

import (
	"fmt"
	"sync"
)

type Account struct {
	Balance int64
	Mutex   *sync.Mutex
}

func (a *Account) Deposit(amount int64) {
	a.Mutex.Lock()
	defer a.Mutex.Unlock()
	a.Balance += amount
}

func (a *Account) Withdraw(amount int64) error {
	a.Mutex.Lock()
	defer a.Mutex.Unlock()
	if a.Balance < amount {
		return fmt.Errorf("insufficient balance")
	}
	a.Balance -= amount
	return nil
}

var accounts = make(map[string]*Account)

func main() {
	account1 := &Account{Balance: 100, Mutex: &sync.Mutex{}}
	account2 := &Account{Balance: 200, Mutex: &sync.Mutex{}}

	accounts["account1"] = account1
	accounts["account2"] = account2

	go func() {
		account1.Deposit(50)
	}()

	go func() {
		result := account2.Withdraw(150)
		if result != nil {
			fmt.Println(result)
		}
	}()

	var wg sync.WaitGroup
	wg.Add(2)

	go func() {
		defer wg.Done()
		for i := 0; i < 10000; i++ {
			account1.Deposit(1)
		}
	}()

	go func() {
		defer wg.Done()
		for i := 0; i < 10000; i++ {
			result := account2.Withdraw(1)
			if result != nil {
				fmt.Println(result)
			}
		}
	}()

	wg.Wait()

	fmt.Printf("Account 1 Balance: %d\n", accounts["account1"].Balance)
	fmt.Printf("Account 2 Balance: %d\n", accounts["account2"].Balance)
}